// Models groups the package's query handles under one database scope.
// It is safe to reuse when its DBTX implementation supports concurrent use.
type Models struct {
	Users       *UserQuery
	Profiles    *ProfileQuery
	Teams       *TeamQuery
	Memberships *MembershipQuery
	Projects    *ProjectQuery
	Posts       *PostQuery
	Comments    *CommentQuery
	Tags        *TagQuery
	PostTags    *PostTagQuery
	Activities  *ActivityQuery
}

func NewModels(db DBTX) *Models {
	return &Models{
		Users:       Users(db),
		Profiles:    Profiles(db),
		Teams:       Teams(db),
		Memberships: Memberships(db),
		Projects:    Projects(db),
		Posts:       Posts(db),
		Comments:    Comments(db),
		Tags:        Tags(db),
		PostTags:    PostTags(db),
		Activities:  Activities(db),
	}
}

// With returns the same set of query handles scoped to another connection or transaction.
func (m *Models) With(db DBTX) *Models { return NewModels(db) }
